import { usePromise } from '#registry/default/hooks/use-promise.ts';

const loadedModules: Map<string, unknown> = new Map();
const loadPromises: Map<string, Promise<unknown>> = new Map();

/** Loads a module once and caches it by key, returning the same promise for subsequent calls. */
export function getLazyModule<T>(moduleKey: string, loadFn: () => Promise<T>) {
  function load() {
    const loadedModule = loadedModules.get(moduleKey) as T;
    if (loadedModule) return Promise.resolve(loadedModule);

    return loadFn().then(module => {
      loadedModules.set(moduleKey, module);
      return module;
    });
  }

  const loadPromise = loadPromises.get(moduleKey) as Promise<T> | undefined;
  if (loadPromise) return loadPromise;

  const res = load();
  loadPromises.set(moduleKey, res);
  return res;
}

export type LazyModuleOptions = {
  disabled?: boolean;
  suspend?: boolean;
};

export type LazyModuleHookOptions<T = unknown> = LazyModuleOptions & {
  preloadedModule?: T;
};

type UseLazyModuleOptions<T = unknown> = LazyModuleHookOptions<T> & {
  moduleKey: string;
  moduleLoadFn: () => Promise<T>;
};

/** Lazily loads a module by key and returns its instance once resolved (optionally suspending). */
export function useLazyModule<T = unknown>({
  disabled = false,
  suspend = false,
  preloadedModule,
  moduleKey,
  moduleLoadFn,
}: UseLazyModuleOptions<T>) {
  const promise = disabled || preloadedModule ? undefined : getLazyModule(moduleKey, moduleLoadFn);
  const instance = preloadedModule ?? (loadedModules.get(moduleKey) as T | undefined);
  const res = usePromise(promise, instance, suspend);
  return res;
}
